import { useState } from "react";
import { motion } from "framer-motion";
import { Wine, Beer, Martini, UtensilsCrossed, Flame, IceCream } from "lucide-react";
import Footer from "../components/Footer";

// Menu Categories and Items
const menuCategories = [
  {
    id: "salad",
    name: "Salad",
    icon: UtensilsCrossed,
    items: [
      { name: "Classic Caesar Salad", price: "₹429" },
      { name: "Fruit Salad", price: "₹449" },
      { name: "Burrata Arugula Salad", price: "₹850" },
      { name: "Green Salad", price: "₹199" },
    ]
  },
  {
    id: "sushi",
    name: "Sushi",
    icon: UtensilsCrossed,
    items: [
      { name: "Shiitake Mushroom Nigiri", price: "₹499" },
      { name: "Veg California Roll", price: "₹549" },
      { name: "Edamame California Roll", price: "₹549" },
      { name: "Avocado Tempura Uramaki", price: "₹549" },
      { name: "Crab Stick Nigiri", price: "₹499" },
      { name: "Prawn Tempura Uramaki", price: "₹599" },
      { name: "Chicken Teriyaki Futomaki", price: "₹599" },
      { name: "Smoked Salmon Maki", price: "₹699" },
    ]
  },
  {
    id: "fries-nachos",
    name: "Fries & Nachos",
    icon: Flame,
    items: [
      { name: "Peri Peri Fries", price: "₹249" },
      { name: "Truffle French Fry", price: "₹399" },
      { name: "Loaded Nachos", price: "₹549 / 599" },
    ]
  },
  {
    id: "oriental-starters",
    name: "Oriental Starters",
    icon: Flame,
    items: [
      { name: "Golden Fried Baby Corn", price: "₹199" },
      { name: "Corn Salt & Pepper", price: "₹249" },
      { name: "Crackling Spinach", price: "₹249" },
      { name: "Crispy Chilli Baby Corn", price: "₹299" },
      { name: "Chilli Lotus Stem", price: "₹299" },
      { name: "Sesame Paneer Sticks", price: "₹299" },
      { name: "Crispy Konjee Vegetable", price: "₹349" },
      { name: "Schezwan Paneer Dry", price: "₹399" },
      { name: "Soya Chilli Mushroom", price: "₹449" },
      { name: "Drums of Heaven", price: "₹349" },
      { name: "Honey Chilli Chicken", price: "₹349" },
      { name: "Cilantro Chilli Chicken", price: "₹349" },
      { name: "Chicken Wings", price: "₹349" },
      { name: "Tangra Style Chilli Chicken", price: "₹399" },
      { name: "Chicken Yakitori", price: "₹449" },
      { name: "Steamed Fish", price: "₹449" },
      { name: "Kung Pao Chicken", price: "₹499" },
      { name: "Golden Fried Prawn", price: "₹499" },
      { name: "Butter Chilli Garlic Prawns", price: "₹499" },
      { name: "Pan Fried Chilli Fish", price: "₹599" },
      { name: "Honey Soya Pork Belly", price: "₹599" },
    ]
  },
  {
    id: "pizza",
    name: "Pizza",
    icon: UtensilsCrossed,
    items: [
      { name: "Margherita", price: "₹395" },
      { name: "Pepperoni", price: "₹495" },
      { name: "BBQ Chicken", price: "₹545" },
      { name: "Mushroom & Truffle", price: "₹595" },
      { name: "Four Cheese", price: "₹545" },
    ]
  },
  {
    id: "cocktails",
    name: "Signature Cocktails",
    icon: Martini,
    items: [
      { name: "Corridor Special", price: "₹595" },
      { name: "Kolkata Sunset", price: "₹545" },
      { name: "Smoky Old Fashioned", price: "₹645" },
      { name: "Espresso Martini", price: "₹575" },
      { name: "Passion Mojito", price: "₹495" },
      { name: "Mango Margarita", price: "₹545" },
    ]
  },
  {
    id: "beer",
    name: "Beer & More",
    icon: Beer,
    items: [
      { name: "Kingfisher Premium", price: "₹295" },
      { name: "Corona Extra", price: "₹445" },
      { name: "Budweiser", price: "₹345" },
      { name: "Hoegaarden", price: "₹495" },
      { name: "Bira White", price: "₹295" },
      { name: "Guinness Draught", price: "₹545" },
    ]
  },
  {
    id: "desserts",
    name: "Desserts",
    icon: IceCream,
    items: [
      { name: "Chocolate Lava Cake", price: "₹345" },
      { name: "Tiramisu", price: "₹325" },
      { name: "New York Cheesecake", price: "₹295" },
      { name: "Brownie Sundae", price: "₹325" },
    ]
  }
];

// ✅ IMAGE PATHS (keep images inside /public/assets/menu_images/)
const categoryImages = {
  salad: "/assets/menu_images/salad.jpg",
  sushi: "/assets/menu_images/sushi.jpg",
  "fries-nachos": "/assets/menu_images/fries_nachos.jpg",
  "oriental-starters": "/assets/menu_images/oriental_starters.jpg",
  pizza: "/assets/menu_images/pizza.jpg",
  cocktails: "/assets/menu_images/cocktails.jpg",
  beer: "/assets/menu_images/beer.jpg",
  desserts: "/assets/menu_images/dessert.jpg",
};

const MenuPage = () => {
  const [activeCategory, setActiveCategory] = useState("salad");

  const activeMenuCategory = menuCategories.find(
    (cat) => cat.id === activeCategory
  );

  return (
    <main className="bg-black min-h-screen pt-24 md:pt-32">

      {/* Category Navigation */}
      <section className="max-w-[1400px] mx-auto px-6 md:px-12 pb-8">
        <div className="flex flex-wrap justify-center gap-3 md:gap-4">
          {menuCategories.map((category) => {
            const IconComponent = category.icon;
            return (
              <button
                key={category.id}
                onClick={() => setActiveCategory(category.id)}
                className={`flex items-center gap-2 px-4 py-2 border ${
                  activeCategory === category.id
                    ? "bg-yellow-500 text-black"
                    : "text-white border-gray-600"
                }`}
              >
                <IconComponent size={16} />
                {category.name}
              </button>
            );
          })}
        </div>
      </section>

      {/* Content */}
      <section className="max-w-[1400px] mx-auto px-6 md:px-12 pb-24">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

          {/* ✅ FIXED IMAGE BLOCK */}
          <div className="lg:col-span-1">
            <div className="relative aspect-[3/4] overflow-hidden border border-zinc-800">

              <img
                src={categoryImages?.[activeCategory] || "/assets/menu_images/default.jpg"}
                alt={activeMenuCategory?.name || "Menu"}
                className="w-full h-full object-cover"
                loading="lazy"
                onError={(e) => {
                  e.target.src =
                    "https://images.unsplash.com/photo-1546069901-ba9599a7e63c";
                }}
              />

              <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />

              <div className="absolute bottom-0 left-0 p-4">
                <h3 className="text-white text-2xl">
                  {activeMenuCategory?.name}
                </h3>
              </div>
            </div>
          </div>

          {/* Items */}
          <div className="lg:col-span-2">
            {activeMenuCategory?.items.map((item, i) => (
              <div key={i} className="border-b border-gray-700 p-4 flex justify-between">
                <span className="text-white">{item.name}</span>
                <span className="text-yellow-400">{item.price}</span>
              </div>
            ))}
          </div>

        </div>
      </section>

      <Footer />
    </main>
  );
};

export default MenuPage;
